package com.i2i.voltwise.home;
import com.fasterxml.jackson.databind.ObjectMapper; import com.i2i.voltwise.audit.SnapshotRepository; import com.i2i.voltwise.home.HomeDtos.*; import com.i2i.voltwise.state.LiveStateService; import jakarta.transaction.Transactional; import org.springframework.beans.factory.annotation.Value; import org.springframework.kafka.core.KafkaTemplate; import org.springframework.stereotype.Service; import java.time.*; import java.util.*; import java.util.stream.Collectors;
@Service public class HomeService { private final HomeRepository homes; private final SnapshotRepository snapshots; private final LiveStateService live; private final KafkaTemplate<String,String> kafka; private final ObjectMapper json; @Value("${voltwise.kafka.registration-topic}") String registrationTopic; public HomeService(HomeRepository homes,SnapshotRepository snapshots,LiveStateService live,KafkaTemplate<String,String> kafka,ObjectMapper json){this.homes=homes;this.snapshots=snapshots;this.live=live;this.kafka=kafka;this.json=json;} @Transactional public CreatedHome create(CreateHomeRequest r){var h=new Home(UUID.randomUUID(),r.name(),r.email(),r.budgetLimit(),r.baseTariff(),r.penaltyMultiplier());r.appliances().forEach(a->h.appliances.add(new Appliance(UUID.randomUUID(),h,a.name(),a.safeWattLimit())));homes.save(h);live.register(h);try{kafka.send(registrationTopic,h.id.toString(),json.writeValueAsString(Map.of("homeId",h.id,"name",h.name,"appliances",h.appliances.stream().map(a->Map.of("id",a.id,"name",a.name,"safeWattLimit",a.safeWattLimit)).toList())));}catch(Exception e){throw new IllegalStateException("Kayıt olayı yayınlanamadı",e);}return new CreatedHome(h.id,h.name);} public List<DailyTrend> history(UUID homeId,int days){if(!homes.existsById(homeId))throw new NoSuchElementException("Ev bulunamadı");return snapshots.findRecent(homeId,Instant.now().minus(Duration.ofDays(days))).stream().collect(Collectors.groupingBy(s->s.capturedAt.atZone(ZoneOffset.UTC).toLocalDate(),TreeMap::new,Collectors.toList())).entrySet().stream().map(e->new DailyTrend(e.getKey(),e.getValue().stream().mapToDouble(s->s.energyKwh.doubleValue()).max().orElse(0),e.getValue().stream().mapToDouble(s->s.cost.doubleValue()).max().orElse(0))).toList();} }
